---


Author Name: **Frederic Requin**
Original Redmine Message: 1198 from https://www.veripool.org



---

Hello,

I am experimenting simulation with Lattice ECP3 DDR memory interface.
Here is what I had to do to make it work :
1. rewrite Lattice's primitives to make them verilator friendly (lots of negedge FF, posedge FF and latches in their DDR elements)
1. have 16 simulation "steps" per clock period (8 or 4 might be enough but I needed additional shifted clocks)
1. use DPI-C interface to create delayed signal (is there another way to do that ?)
1. call the verilated model twice (before and after the call to the DDR SDRAM C++ model) to have the correct behaviour during DDR read cmds.

The testbench main loop looks like that:
```
  // Initialize simulation inputs
  top->RST       = 1;
  top->SYSCLK    = 0;
  top->DDRCLK    = 0;

  sys_clk_ctr    = 0;  // SYSCLK counter (0 - 15)
  ddr_clk_ctr    = 4;  // DDRCLK counter (0 - 15)
  tb_sstep       = 0;  // Simulation steps (64 bits)

  // Run simulation for NUM_STEPS steps
  while (tb_sstep < NUM_STEPS)
  {
     // Toggle clocks and manage resets
     top->SYSCLK  = (sys_clk_ctr >> 3) & 1;               // 166 MHz system clock
     top->DDRCLK  = (ddr_clk_ctr >> 3) & 1;               // 166 MHz DDR clock
     top->RST     = (tb_sstep < (vluint64_t)128) ? 1 : 0; // 8 SYSCLK cycles

     // Evaluate verilated model
     top->eval ();

     // Evaluate DDR1 SDRAM C++ model
     ddr->eval (tb_sstep / 16,
                top->DDR_CLK_P, top->DDR_CLK_N,   (vluint8_t)1,
                top->DDR_CSN,   top->DDR_RASN,    top->DDR_CASN,   top->DDR_WEN,
                top->DDR_BANK,  top->DDR_ADDR,
                (vluint8_t)0,   top->DDR_DQS_OUT, top->DDR_DQ_OUT, sdram_dqs, sdram_dq
                );

     // "Read" from DDR1 SDRAM
     top->DDR_DQS_IN = (top->DDR_DQS_OE_N) ? sdram_dqs : top->DDR_DQS_OUT;
     top->DDR_DQ_IN  = (top->DDR_DQ_OE_N)  ? sdram_dq  : top->DDR_DQ_OUT;

     // Evaluate verilated model one more time
     top->eval ();

#if VM_TRACE
     // Dump signals into VCD file
     if (tfp) tfp->dump (tb_sstep * STEP_PS);
#endif

     // Next simulation step
     sys_clk_ctr = (sys_clk_ctr + 1) & 15;
     ddr_clk_ctr = (ddr_clk_ctr + 1) & 15;
     tb_sstep++;
  }

```
Is it normal that I have to call the model twice ? Is it safe ? Can I do it differently ?

As for the DPI-C delay implementation, I am not proud of it but it works.

Here is a snippet of the verilog file :
```
     // Quarter period delay :
`ifdef verilator3 
     // Done with DPI-C
     import "DPI-C" pure    function longint sim_step ();
     import "DPI-C" context function bit     delay_sig (integer idx, input longint dly, input bit sig);

     longint  sclk_rise;
     longint  sclk_qper;
     reg      sclk_meas;

     initial
     begin
         sclk_rise = 0;
         sclk_qper = 2;
         sclk_meas = 1'b0;
     end

     always@(posedge w_SCLKb)
     begin
         sclk_rise = sim_step();
         sclk_meas = 1'b1;
     end

     always@(negedge w_SCLKb)
     begin
         if (sclk_meas) sclk_qper = (sim_step() - sclk_rise) / 2;
     end

     // Cell #210
     always@(w_DQSDELb or w_DQSIb or w_SCLKb)
     begin
         if (w_DQSDELb) begin
             // Slave delay ON
             r_DQSW   = delay_sig(0, sclk_qper,     w_SCLKb);
         end else begin
             // Slave delay OFF
             r_DQSW   = w_SCLKb;
         end
     end    
`else
     realtime sclk_rise;
     realtime sclk_qper;
     reg      sclk_meas;

     initial
     begin
         sclk_rise = 0.0;
         sclk_qper = 1.5;
         sclk_meas = 1'b0;
     end

     always@(posedge w_SCLKb)
     begin
         sclk_rise = $realtime;
         sclk_meas = 1'b1;
     end

     always@(negedge w_SCLKb)
     begin
         if (sclk_meas) sclk_qper = ($realtime - sclk_rise) / 2;
     end

     // Cell #210
     always@(w_DQSDELb or w_DQSIb or w_SCLKb)
     begin
         if (w_DQSDELb) begin
             // Slave delay ON
             r_DQSW   <= #sclk_qper w_SCLKb;
         end else begin
             // Slave delay OFF
             r_DQSW   <= w_SCLKb;
         end
     end
`endif

```
Here is the C file :
```
#include "svdpi.h"
#include "verilated.h"

#ifdef __cplusplus
extern "C" {
#endif

extern vluint64_t tb_sstep;

// Return the current simulation step number
long long sim_step(void)
{
     return (long long)tb_sstep;
}

// Delay signal by "dly" simulation steps
unsigned char delay_sig(int idx, long long dly, unsigned char sig)
{
     static long long     cur_sstep[16];
     static unsigned long dly_line[16];

     if (0 == tb_sstep)
     {
         // Initial value
         cur_sstep[idx & 15] = 0;
         dly_line[idx & 15]  = (unsigned long)sig;
     }
     else if (cur_sstep[idx & 15] != tb_sstep)
     {
         // New simulation step
         cur_sstep[idx & 15] = tb_sstep;
         dly_line[idx & 15]  = (dly_line[idx & 15] << 1) | (unsigned long)sig;
     }

     return (unsigned char)((dly_line[idx & 15] >> (int)dly) & 1);
}

#ifdef __cplusplus
}
#endif

```
As you can see, the main issue is that delay_sig() may be used many times in the same verilog module (this is actually the case, it is used 3 times) and the module can be instantiated many times.

I partially solved the issue by using the parameter "idx" but I should really use the context information (I do not really know how to do it).

One more thing, maybe it is easy to add a $delay(n, sig) function in verilator that delays the signal "sig" by n steps ?

That would be very helpful.

Regards,

Frederic Requin

